import{_ as s,o as e,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Importing Historical User Data","description":"","frontmatter":{"title":"Importing Historical User Data","slug":"importing-historical-user-data"},"headers":[],"relativePath":"developer-hub/importing-historical-user-data.md","filePath":"developer-hub/importing-historical-user-data.md"}'),i={name:"developer-hub/importing-historical-user-data.md"};function o(r,a,l,p,d,c){return e(),t("div",null,[...a[0]||(a[0]=[n(`<p>Any time the Branch SDK sees a user we&#39;ve never seen before, Branch logs a new install record for that user. While perfect for new apps being introduced to the app stores, this presents a problem for existing apps in the app store, but new to Branch.</p><p>If your app already has an established user base before you implement the Branch SDK, you will encounter issues with false positives (new installs) that are actually not new to your app, only new to Branch.</p><p>To avoid unnecessary discrepancies and ensure your existing users are not attributed as new installs, use the Link Data Import Tool to inform Branch about your pre-existing users.</p><div class="info custom-block"><p class="custom-block-title">Enterprise Access Only</p><p>Please note that this feature is only available for Enterprise clients.</p></div><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><p>Format your historical data to adhere to the supported <a href="http://jsonlines.org/" target="_blank" rel="noreferrer">JSON line text format</a>.</p><ul><li>See Import File Format section below for information on required and optional fields.</li><li>Branch can ingest historical data from any source - other attribution providers, third party analytics providers and internal BI systems - as long as this data conforms to the file format requirement containing the mandatory fields.</li></ul></li><li><p>Contact your TAM or Account Executive to begin the import process.</p></li><li><p>Once your historical data has been imported and verified, your TAM or Support contact will send notification of a successful import.</p></li></ol><h2 id="things-to-keep-in-mind" tabindex="-1">Things to Keep in Mind <a class="header-anchor" href="#things-to-keep-in-mind" aria-label="Permalink to &quot;Things to Keep in Mind&quot;">​</a></h2><ul><li><p>Downstream analytics remain unaffected → no spike in installs on day of import.</p></li><li><p>According to our privacy policy, users who have no attribution data recorded on the Branch platform for 30 days after import, or no activity at all for 90 days after import, will be deleted.</p></li><li><p>The following functionality is currently not supported:</p><ul><li>Attribution to clicks that were recorded before import.</li><li>Analysis / viewing of historical data within dashboard or exports.</li></ul></li></ul><h2 id="import-file-format" tabindex="-1">Import File Format <a class="header-anchor" href="#import-file-format" aria-label="Permalink to &quot;Import File Format&quot;">​</a></h2><p>Before Branch can ingest your historical user data, please ensure your data conforms to the <a href="http://jsonlines.org/" target="_blank" rel="noreferrer">JSON line text format</a>.</p><div class="warning custom-block"><p class="custom-block-title">JSON Line Text Format Required</p><p>We are unable to translate or ingest data in other formats.</p></div><h2 id="device-id-based-user-import" tabindex="-1">Device ID Based User Import <a class="header-anchor" href="#device-id-based-user-import" aria-label="Permalink to &quot;Device ID Based User Import&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Device IDs Only</p><p>Providing the following required fields ensures that Branch can create a Persona for each individual user based on the device ID you provide during import.</p><p>An iOS device must have either IDFA, IDFV, or both in order for Branch to ingest it. Likewise, an Android device must have either GAID or Android ID for Branch to ingest it.</p><p>If you don&#39;t have a particular ID or it&#39;s not relevant to the device, please omit the field entirely.</p></div><p>Each individual log should be captured in single line json object including the following fields:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>	&quot;timestamp&quot;: &lt;unix epoch milliseconds long&gt;(required),</span></span>
<span class="line"><span>	&quot;app_id&quot;: &lt;app ID long&gt;(required; your **Branch** App ID found on your Branch dashboard under Account Settings),</span></span>
<span class="line"><span>	&quot;idfa&quot;: &quot;&lt;idfa string&gt;&quot; (IDFA or IDFV is required for iOS devices),</span></span>
<span class="line"><span>	&quot;gaid&quot;: &quot;&lt;google ad id string&gt; (GAID or Android ID is required for Android devices),</span></span>
<span class="line"><span>	&quot;windows_aid&quot;: &quot;&lt;windows ad id string&gt;&quot; (required for Windows devices),</span></span>
<span class="line"><span>	&quot;kindle_aid&quot;: &quot;&lt;kindle hardware id string&gt;&quot; (required for Kindle devices),</span></span>
<span class="line"><span>	&quot;touch_type&quot;: &quot;click/impression&quot; (required if not organic)</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Optional supported fields:</p><div class="info custom-block"><p class="custom-block-title">Optional Fields</p><p>While not required, we do recommend providing additional information to create a more robust user persona as well as fuel other Branch features such as Fraud rules.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;idfv&quot;: &quot;&lt;idfv string&gt;&quot;,</span></span>
<span class="line"><span>“android_id”: &lt;google android id string&gt;,</span></span>
<span class="line"><span>&quot;developer_id&quot;: &quot;&lt;customer user id string&quot;&gt;,</span></span>
<span class="line"><span>&quot;os_version&quot;: string,</span></span>
<span class="line"><span>&quot;sdk_version&quot;: string,</span></span>
<span class="line"><span>&quot;country_code&quot;: string,</span></span>
<span class="line"><span>“region_name&quot;: string,</span></span>
<span class="line"><span>&quot;skip_record&quot;: 0 (=&gt;1 to exclude record from import),</span></span></code></pre></div><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><p>Here&#39;s an example of a device import for an iOS device with Limit Ad Tracking on, so only IDFV is available:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>	&quot;timestamp&quot;: 1600720443123,</span></span>
<span class="line"><span>	&quot;app_id&quot;: 123456789012345678,</span></span>
<span class="line"><span>        &quot;idfv&quot;: &quot;30255BCE-4CDA-4F62-91DC-4758FDFF8512&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="additional-attribution-data-import" tabindex="-1">Additional Attribution Data Import <a class="header-anchor" href="#additional-attribution-data-import" aria-label="Permalink to &quot;Additional Attribution Data Import&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Additional Touch Data</p><p>Providing the following optional touch data fields ensures Branch can associate campaign details of the install event associated with the imported user. This enables downstream install cohorting analytics.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;install&quot;: {</span></span>
<span class="line"><span>           “timestamp”:&lt;unix epoch milliseconds long&gt;,</span></span>
<span class="line"><span>           “touch_data”: {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                  &quot;~campaign&quot;: string</span></span>
<span class="line"><span>                  &quot;~campaign_id&quot;: string</span></span>
<span class="line"><span>                  &quot;~advertising_partner_name&quot;: string</span></span>
<span class="line"><span>                  &quot;~advertising_partner_id&quot;: string</span></span>
<span class="line"><span>                  &quot;~keywords&quot;: array</span></span>
<span class="line"><span>                  …</span></span>
<span class="line"><span>                  …</span></span>
<span class="line"><span>                  *refer to extended list of supported fields in this</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>           “strong_match”: boolean (defaults to false, determines whether subsequent attribution type would be strong/weak, stores click as last_click or weak_match_last_click),</span></span>
<span class="line"><span>           “force_update”: boolean (defaults to false, determines whether to add the attribution data to install cohorts)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	}</span></span></code></pre></div>`,24)])])}const m=s(i,[["render",o]]);export{h as __pageData,m as default};
